"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[2494],{3045(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Version 2 (Modern)","banner":null,"badge":true,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"backend","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Backend-Notes/docs/backend/01_Roadmap","label":"The Modern Backend Engineering Roadmap","docId":"backend/Roadmap","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/02_Walk_the_Path","label":"Walking the Path of a Professional Backend Engineer","docId":"backend/Walk_the_Path","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/03_What_is_a_Backend","label":"What is a Backend?","docId":"backend/What_is_a_Backend","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/04_Benefits","label":"Benefits of Learning Backend Engineering from First Principles","docId":"backend/Benefits","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/05_HTTP","label":"Understanding HTTP for Backend Engineers","docId":"backend/HTTP","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/06_Routing","label":"Routing in Backend Development","docId":"backend/Routing","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/07_Serialization","label":"Serialization and Deserialization in Backend Development","docId":"backend/Serialization","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/08_Authentication","label":"Authentication and Authorization","docId":"backend/Authentication","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/09_Validations","label":"Validations and Transformations","docId":"backend/Validations","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/10_Architecture","label":"Backend Architecture: Controllers, Services, and Middleware","docId":"backend/Architecture","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/11_REST_API","label":"Complete REST API Design","docId":"backend/REST_API","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/12_PostgreSQL","label":"Mastering Databases with PostgreSQL","docId":"backend/PostgreSQL","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/13_Caching","label":"Caching: The Secret Behind It All","docId":"backend/Caching","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/14_Task_Queues","label":"Task Queues and Background Jobs","docId":"backend/Task_Queues","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/Elasticsearch","label":"Full-Text Search with Elasticsearch","docId":"backend/Elasticsearch","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/Error_Handling","label":"Error Handling & Fault-Tolerant Systems","docId":"backend/Error_Handling","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/Config_Management","label":"Production-Grade Configuration Management","docId":"backend/Config_Management","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/Logging_Monitoring","label":"Logging, Monitoring & Observability","docId":"backend/Logging_Monitoring","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/Graceful_Shutdown","label":"Graceful Shutdown","docId":"backend/Graceful_Shutdown","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/security","label":"Backend Security","docId":"backend/Backend_Security","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/scaling-part-1","label":"Backend Scaling & Performance - Part 1","docId":"backend/Scaling_Part_1","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/scaling-part-2","label":"Backend Scaling & Performance - Part 2","docId":"backend/Scaling_Part_2","unlisted":false},{"type":"link","href":"/Backend-Notes/docs/backend/concurrency-and-parallelism","label":"Concurrency & Parallelism for Backend Engineers","docId":"backend/Concurrency_and_Parallelism","unlisted":false}]}]},"docs":{"backend/Architecture":{"id":"backend/Architecture","title":"Backend Architecture: Controllers, Services, and Middleware","description":"A professional backend application is structured into distinct layers to ensure scalability, maintainability, and clear separation of concerns. This layered approach follows the Request Life Cycle from the moment it hits the server until a response is sent.","sidebar":"tutorialSidebar"},"backend/Authentication":{"id":"backend/Authentication","title":"Authentication and Authorization","description":"In backend engineering, securing an application revolves around two fundamental questions:","sidebar":"tutorialSidebar"},"backend/Backend_Security":{"id":"backend/Backend_Security","title":"Backend Security","description":"Security is not just a feature; it is a fundamental mindset that every backend engineer must adopt. In this guide, we will explore the core principles of backend security, common vulnerabilities, and how to defend against them.","sidebar":"tutorialSidebar"},"backend/Benefits":{"id":"backend/Benefits","title":"Benefits of Learning Backend Engineering from First Principles","description":"In a rapidly evolving tech landscape, the most valuable skill a backend engineer can possess is the ability to adapt. Learning from \\"First Principles\\" means focusing on the underlying truths of computing and networking rather than the surface-level syntax of any specific framework or language.","sidebar":"tutorialSidebar"},"backend/Caching":{"id":"backend/Caching","title":"Caching: The Secret Behind It All","description":"Caching is one of the most fundamental concepts in backend engineering. It\'s the process of storing copies of data in a temporary storage location (a cache) so that future requests for that data can be served faster.","sidebar":"tutorialSidebar"},"backend/Concurrency_and_Parallelism":{"id":"backend/Concurrency_and_Parallelism","title":"Concurrency & Parallelism for Backend Engineers","description":"Every backend system faces a core requirement: the ability to handle multiple tasks simultaneously. Without this, a server would be limited to processing one request at a time, leading to significant delays or errors for all other users.","sidebar":"tutorialSidebar"},"backend/Config_Management":{"id":"backend/Config_Management","title":"Production-Grade Configuration Management","description":"Configuration management is the systematic approach to organizing and accessing all the settings of a backend application. Think of it as the DNA of your application\u2014it dictates how your code behaves across different environments without requiring code changes.","sidebar":"tutorialSidebar"},"backend/Elasticsearch":{"id":"backend/Elasticsearch","title":"Full-Text Search with Elasticsearch","description":"In the early days of the web, searching through a few thousand products was a simple task for traditional relational databases using basic LIKE queries. However, as data scales to millions of records and user expectations shift toward \\"smart\\" search, relevance, and typo tolerance, traditional databases often fall short. This is where dedicated search engines like Elasticsearch become essential.","sidebar":"tutorialSidebar"},"backend/Error_Handling":{"id":"backend/Error_Handling","title":"Error Handling & Fault-Tolerant Systems","description":"In backend engineering, errors are not exceptions; they are an inevitable part of the system\'s lifecycle. Building a fault-tolerant system requires moving beyond simply \\"fixing bugs\\" to adopting a proactive mindset where failure is anticipated and managed.","sidebar":"tutorialSidebar"},"backend/Graceful_Shutdown":{"id":"backend/Graceful_Shutdown","title":"Graceful Shutdown","description":"In production systems, servers frequently restart due to deployments, scaling events, or infrastructure maintenance. Graceful Shutdown is the practice of ensuring these restarts don\'t interrupt ongoing work, corrupt data, or degrade the user experience.","sidebar":"tutorialSidebar"},"backend/HTTP":{"id":"backend/HTTP","title":"Understanding HTTP for Backend Engineers","description":"HTTP (Hypertext Transfer Protocol) is the foundation of data communication on the World Wide Web. For backend engineers, a deep understanding of HTTP is essential, as it defines how clients and servers interact, exchange data, and manage state.","sidebar":"tutorialSidebar"},"backend/Logging_Monitoring":{"id":"backend/Logging_Monitoring","title":"Logging, Monitoring & Observability","description":"In modern distributed systems, understanding what is happening inside your backend is critical. Logging, monitoring, and observability are not just tools; they are practices implemented on a spectrum to ensure system reliability and ease of debugging.","sidebar":"tutorialSidebar"},"backend/PostgreSQL":{"id":"backend/PostgreSQL","title":"Mastering Databases with PostgreSQL","description":"Databases are the foundation of any backend system. Understanding how to model, query, and optimize data storage is critical for building scalable applications.","sidebar":"tutorialSidebar"},"backend/REST_API":{"id":"backend/REST_API","title":"Complete REST API Design","description":"REST (Representational State Transfer) is the industry-standard architectural style for building scalable web APIs. Designing a professional API requires more than just making it work; it must be intuitive, consistent, and standard-compliant.","sidebar":"tutorialSidebar"},"backend/Roadmap":{"id":"backend/Roadmap","title":"The Modern Backend Engineering Roadmap","description":"Backend engineering is a comprehensive discipline that extends far beyond building simple CRUD (Create, Read, Update, Delete) APIs. It encompasses the design and implementation of reliable, scalable, fault-tolerant, and maintainable systems.","sidebar":"tutorialSidebar"},"backend/Routing":{"id":"backend/Routing","title":"Routing in Backend Development","description":"Routing is the mechanism that maps incoming HTTP requests to specific server-side logic, known as handlers. It is essentially the \\"address system\\" of your backend, determining where a request should go based on its destination and intent.","sidebar":"tutorialSidebar"},"backend/Scaling_Part_1":{"id":"backend/Scaling_Part_1","title":"Backend Scaling & Performance - Part 1","description":"Scaling and performance are two of the most critical aspects of backend engineering. Understanding how to measure performance and how systems behave under load is essential for building robust infrastructure.","sidebar":"tutorialSidebar"},"backend/Scaling_Part_2":{"id":"backend/Scaling_Part_2","title":"Backend Scaling & Performance - Part 2","description":"While Part 1 covered the basics of performance metrics and fundamental optimization, Part 2 dives into the architectural shifts required to scale a backend horizontally.","sidebar":"tutorialSidebar"},"backend/Serialization":{"id":"backend/Serialization","title":"Serialization and Deserialization in Backend Development","description":"Serialization and Deserialization is the process of converting data structures or object states into a format that can be stored or transmitted and later reconstructed. In backend engineering, this is the \\"bridge\\" that allows different systems, often written in different programming languages, to communicate seamlessly.","sidebar":"tutorialSidebar"},"backend/Task_Queues":{"id":"backend/Task_Queues","title":"Task Queues and Background Jobs","description":"In backend engineering, not every task needs to be completed within the context of a single request-response cycle. Background jobs and task queues are essential for building responsive, scalable, and reliable applications.","sidebar":"tutorialSidebar"},"backend/Validations":{"id":"backend/Validations","title":"Validations and Transformations","description":"Validations and transformations are critical for maintaining Data Integrity and Security. They act as a protective layer at the entry point of your server (the Controller Layer), ensuring that data is in the expected format before it reaches your business logic.","sidebar":"tutorialSidebar"},"backend/Walk_the_Path":{"id":"backend/Walk_the_Path","title":"Walking the Path of a Professional Backend Engineer","description":"Becoming a proficient backend engineer is a journey of mastering systems, protocols, and architectural patterns. It requires a shift from simply \\"writing code\\" to \\"designing systems\\" that are resilient, performant, and secure.","sidebar":"tutorialSidebar"},"backend/What_is_a_Backend":{"id":"backend/What_is_a_Backend","title":"What is a Backend?","description":"In the context of modern web and mobile applications, the \\"backend\\" refers to the part of the system that remains invisible to the end user but is responsible for the heavy lifting: data processing, business logic, and security.","sidebar":"tutorialSidebar"}}}}')}}]);